// WebGPU compat test #13 — a multi-LAYER chained forward proving GPUBuffer
// RESIDENCY across layers under monster (the engine's resident-GPUBuffer path).
//
// The CPU keystone's fatal flaw was re-uploading weights per call; the WebGPU
// engine keeps weights + the residual stream RESIDENT as GPUBuffers across every
// layer. This test models a tiny transformer block stack: weight buffers (Q8_0
// matvec W + F32 norm gamma) are written to the GPU ONCE, then NUM_LAYERS blocks
// run as separate command encoders/submits that all read the same resident
// weight buffers and read-modify-write the same resident residual buffer. If
// residency held, the GPU result equals the CPU reference that walks the same
// block recurrence. Golden-diffed monster vs the Deno real-navigator.gpu oracle.
//
// Per block (hidden dim H): r = RMSNorm(r, gamma); h = Wq8 · r; r = r + h.
// (RMSNorm + Q8_0 matvec + residual add — the three resident-buffer kernels
// already golden in tests 07/08/11, now chained with NO re-upload between layers.)
//
// Inline pure-JS encoders; single-declarator consts (monster gap); sign-stable q4.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function f16bytes(x) {
  if (x === 0) return [0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 15) | ((e + 15) << 10) | (Math.round((m - 1) * Math.pow(2, 10)) & 0x3ff)) & 0xffff;
  return [bits & 0xff, (bits >>> 8) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function i8byte(q) { return ((q | 0) & 0xff); }
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

const H = 32;            // hidden dim = exactly one Q8_0 block per matvec row
const NUM_LAYERS = 4;    // chain 4 blocks across separate submits
const EPS = 0.000001;

// Resident weights, distinct per layer (so a residency bug — reusing a stale
// buffer or dropping state — produces a clearly wrong recurrence, not a lucky
// pass). W[layer] is H×H Q8_0; gamma[layer] is F32[H].
function scaleOf(layer) { return layer % 2 === 0 ? 0.0625 : 0.125; } // half-exact, tiny → stable
function qOf(layer, row, col) { return (((row + col + layer) % 7) - 3); } // -3..3
function gammaOf(layer, i) { return 1 + ((i + layer) % 5) * 0.03125; }    // ~1, half-exact
function r0(i) { return ((i % 9) - 4) * 0.125; } // initial residual, -0.5..0.5

const BYTES_PER_ROW = 34;                 // 1 Q8_0 block
const PADDED = Math.ceil(BYTES_PER_ROW / 4) * 4; // 36
const WORDS_PER_ROW = PADDED / 4;         // 9
const W_BYTES = H * PADDED;               // per layer

// Pack one layer's Q8_0 weight bytes.
function packW(layer) {
  let wb = [];
  for (let row = 0; row < H; row++) {
    let rb = [];
    rb = rb.concat(f16bytes(scaleOf(layer)));
    for (let c = 0; c < 32; c++) rb = rb.concat([i8byte(qOf(layer, row, c))]);
    while (rb.length < PADDED) rb = rb.concat([0]);
    wb = wb.concat(rb);
  }
  return new Uint8Array(wb);
}
function packGamma(layer) {
  let gb = [];
  for (let i = 0; i < H; i++) gb = gb.concat(f32bytes(gammaOf(layer, i)));
  return new Uint8Array(gb);
}

// ── Resident buffers: weights uploaded ONCE, never re-written in the layer loop ─
const wBufs = [];
const gBufs = [];
for (let layer = 0; layer < NUM_LAYERS; layer++) {
  const wb = device.createBuffer({ size: W_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(wb, 0, packW(layer));
  wBufs.push(wb);
  const gb = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(gb, 0, packGamma(layer));
  gBufs.push(gb);
}

// Resident activation buffers (also persistent across layers):
//   rA/rB — the residual stream, PING-PONGED each layer. WebGPU forbids binding
//           the same buffer as both `read` and `read_write` in one dispatch
//           (monster correctly panics on the alias; Deno's wgpu silently no-ops
//           the write), so the residual add reads the current residual and
//           writes the OTHER buffer; we swap which is "current" each layer. Both
//           are equally resident across submits — residency is what's under test.
//   nBuf  — RMSNorm output (scratch, overwritten each layer)
//   hBuf  — matvec output (scratch, overwritten each layer)
const rA = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST | GPUBufferUsage.COPY_SRC });
const rB = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST | GPUBufferUsage.COPY_SRC });
{
  let rb = [];
  for (let i = 0; i < H; i++) rb = rb.concat(f32bytes(r0(i)));
  device.queue.writeBuffer(rA, 0, new Uint8Array(rb));
}
const nBuf = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const hBuf = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const resid = [rA, rB];
let cur = 0; // index of the buffer holding the current residual

// Uniforms (constant across layers).
const normDimBuf = device.createBuffer({ size: 8, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(normDimBuf, 0, new Uint8Array(u32bytes(H).concat(f32bytes(EPS))));
const matDimBuf = device.createBuffer({ size: 20, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(matDimBuf, 0, new Uint8Array(
  u32bytes(H).concat(u32bytes(H)).concat(u32bytes(1)).concat(u32bytes(WORDS_PER_ROW)).concat(u32bytes(H))));
const addDimBuf = device.createBuffer({ size: 4, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(addDimBuf, 0, new Uint8Array(u32bytes(H)));

// ── Pipelines (compiled once, reused every layer) ──
const WGSL_RMSNORM = `
struct NormDims { n: u32, eps: f32 };
@group(0) @binding(0) var<storage, read> x: array<f32>;
@group(0) @binding(1) var<storage, read> weight: array<f32>;
@group(0) @binding(2) var<storage, read_write> out: array<f32>;
@group(0) @binding(3) var<uniform> d: NormDims;
var<workgroup> partial: array<f32, 256>;
@compute @workgroup_size(256, 1, 1)
fn main(@builtin(local_invocation_id) lid: vec3<u32>) {
  let tid = lid.x;
  var s: f32 = 0.0;
  var i: u32 = tid;
  loop { if (i >= d.n) { break; } let v = x[i]; s = s + v * v; i = i + 256u; }
  partial[tid] = s;
  workgroupBarrier();
  var stride: u32 = 128u;
  loop { if (stride == 0u) { break; } if (tid < stride) { partial[tid] = partial[tid] + partial[tid + stride]; } workgroupBarrier(); stride = stride >> 1u; }
  let inv = inverseSqrt(partial[0] / f32(d.n) + d.eps);
  var j: u32 = tid;
  loop { if (j >= d.n) { break; } out[j] = x[j] * inv * weight[j]; j = j + 256u; }
}
`;
const WGSL_MATVEC = `
fn f16_to_f32(h: u32) -> f32 {
  let sign = (h >> 15u) & 1u; let exp = (h >> 10u) & 0x1Fu; let frac = h & 0x3FFu;
  var val: f32;
  if (exp == 0u) { val = (f32(frac) / 1024.0) * 0.00006103515625; }
  else if (exp == 0x1Fu) { val = select(3.0e38, 0.0, frac != 0u); }
  else { val = (1.0 + f32(frac) / 1024.0) * exp2(f32(i32(exp) - 15)); }
  return select(val, -val, sign == 1u);
}
fn s8(b: u32) -> i32 { return (i32(b) << 24) >> 24; }
struct Dims { rows: u32, cols: u32, blocksPerRow: u32, wordsPerRow: u32, dispatchRowsX: u32 };
@group(0) @binding(0) var<storage, read> w: array<u32>;
@group(0) @binding(1) var<storage, read> x: array<f32>;
@group(0) @binding(2) var<storage, read_write> y: array<f32>;
@group(0) @binding(3) var<uniform> d: Dims;
fn wbyte(off: u32) -> u32 { let word = w[off >> 2u]; let shift = (off & 3u) * 8u; return (word >> shift) & 0xFFu; }
var<workgroup> partial: array<f32, 64>;
@compute @workgroup_size(64, 1, 1)
fn main(@builtin(workgroup_id) wid: vec3<u32>, @builtin(local_invocation_id) lid: vec3<u32>) {
  let row = wid.x + wid.y * d.dispatchRowsX;
  let tid = lid.x;
  if (row >= d.rows) { return; }
  let rowByteBase = row * d.wordsPerRow * 4u;
  var acc: f32 = 0.0;
  var b: u32 = tid;
  loop {
    if (b >= d.blocksPerRow) { break; }
    let blockBase = rowByteBase + b * 34u;
    let scale = f16_to_f32(wbyte(blockBase) | (wbyte(blockBase + 1u) << 8u));
    let qbase = blockBase + 2u;
    let col = b * 32u;
    for (var i: u32 = 0u; i < 32u; i = i + 1u) { let q = s8(wbyte(qbase + i)); acc = acc + scale * f32(q) * x[col + i]; }
    b = b + 64u;
  }
  partial[tid] = acc;
  workgroupBarrier();
  var stride: u32 = 32u;
  loop { if (stride == 0u) { break; } if (tid < stride) { partial[tid] = partial[tid] + partial[tid + stride]; } workgroupBarrier(); stride = stride >> 1u; }
  if (tid == 0u) { y[row] = partial[0]; }
}
`;
const WGSL_ADD = `
struct N { n: u32 };
@group(0) @binding(0) var<storage, read> a: array<f32>;
@group(0) @binding(1) var<storage, read> b: array<f32>;
@group(0) @binding(2) var<storage, read_write> out: array<f32>;
@group(0) @binding(3) var<uniform> d: N;
@compute @workgroup_size(64,1,1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) { let i = gid.x; if (i >= d.n) { return; } out[i] = a[i] + b[i]; }
`;

const normMod = device.createShaderModule({ code: WGSL_RMSNORM });
const normPipe = device.createComputePipeline({ layout: 'auto', compute: { module: normMod, entryPoint: 'main' } });
const matMod = device.createShaderModule({ code: WGSL_MATVEC });
const matPipe = device.createComputePipeline({ layout: 'auto', compute: { module: matMod, entryPoint: 'main' } });
const addMod = device.createShaderModule({ code: WGSL_ADD });
const addPipe = device.createComputePipeline({ layout: 'auto', compute: { module: addMod, entryPoint: 'main' } });

// ── The chained layer loop. Each layer is its OWN command encoder + submit, so
// passing state forward REQUIRES the GPUBuffers to stay resident between submits.
for (let layer = 0; layer < NUM_LAYERS; layer++) {
  const src = resid[cur];
  const dst = resid[1 - cur];
  // RMSNorm(src, gamma[layer]) -> nBuf
  const normBg = device.createBindGroup({ layout: normPipe.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: src } }, { binding: 1, resource: { buffer: gBufs[layer] } },
    { binding: 2, resource: { buffer: nBuf } }, { binding: 3, resource: { buffer: normDimBuf } }] });
  // matvec(W[layer], nBuf) -> hBuf
  const matBg = device.createBindGroup({ layout: matPipe.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: wBufs[layer] } }, { binding: 1, resource: { buffer: nBuf } },
    { binding: 2, resource: { buffer: hBuf } }, { binding: 3, resource: { buffer: matDimBuf } }] });
  // add(src, hBuf) -> dst  (residual update into the OTHER resident buffer)
  const addBg = device.createBindGroup({ layout: addPipe.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: src } }, { binding: 1, resource: { buffer: hBuf } },
    { binding: 2, resource: { buffer: dst } }, { binding: 3, resource: { buffer: addDimBuf } }] });

  const enc = device.createCommandEncoder();
  const p1 = enc.beginComputePass(); p1.setPipeline(normPipe); p1.setBindGroup(0, normBg); p1.dispatchWorkgroups(1, 1, 1); p1.end();
  const p2 = enc.beginComputePass(); p2.setPipeline(matPipe); p2.setBindGroup(0, matBg); p2.dispatchWorkgroups(H, 1, 1); p2.end();
  const p3 = enc.beginComputePass(); p3.setPipeline(addPipe); p3.setBindGroup(0, addBg); p3.dispatchWorkgroups(Math.ceil(H / 64), 1, 1); p3.end();
  device.queue.submit([enc.finish()]);
  cur = 1 - cur; // dst becomes the current residual for the next layer
}

// Read back the final resident residual.
const readBuf = device.createBuffer({ size: H * 4, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
{
  const enc = device.createCommandEncoder();
  enc.copyBufferToBuffer(resid[cur], 0, readBuf, 0, H * 4);
  device.queue.submit([enc.finish()]);
}
await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let gpu = [];
for (let i = 0; i < H; i++) { const o = i * 4; gpu = gpu.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
readBuf.unmap();

// ── CPU reference: walk the same block recurrence on the host. ──
let r = [];
for (let i = 0; i < H; i++) r = r.concat([r0(i)]);
for (let layer = 0; layer < NUM_LAYERS; layer++) {
  // RMSNorm
  let ss = 0;
  for (let i = 0; i < H; i++) ss += r[i] * r[i];
  const inv = 1 / Math.sqrt(ss / H + EPS);
  const n = [];
  for (let i = 0; i < H; i++) n.push(r[i] * inv * gammaOf(layer, i));
  // matvec: h[row] = sum_col scale * q[row,col] * n[col]
  const h = [];
  for (let row = 0; row < H; row++) {
    let acc = 0;
    for (let c = 0; c < 32; c++) acc += scaleOf(layer) * qOf(layer, row, c) * n[c];
    h.push(acc);
  }
  // residual add
  for (let i = 0; i < H; i++) r[i] = r[i] + h[i];
}

out.layers = NUM_LAYERS;
out.gpu = gpu.map(q4);
out.cpu = r.map(q4);
let dmax = 0;
for (let i = 0; i < H; i++) { const dd = Math.abs(gpu[i] - r[i]); if (dd > dmax) dmax = dd; }
out.maxAbsDiff = q4(dmax);
console.error('RAW gpu[0..4]=' + JSON.stringify(gpu.slice(0, 4)) + ' cpu[0..4]=' + JSON.stringify(r.slice(0, 4)) + ' maxdiff=' + dmax);
console.log('__RESULT__ ' + JSON.stringify(out));
